import pytest
import requests

def test_submit_valid_timesheet_typical_week(auth_fixture, base_url):
    token = auth_fixture()
    payload = {
        "week": {
            "mon": 8, "tue": 8, "wed": 8,
            "thu": 8, "fri": 8, "sat": 0, "sun": 0
        }
    }
    resp = requests.post(
        f"{base_url}/timesheets/submit",
        json=payload,
        headers={"Authorization": f"Bearer {token}"}
    )
    assert resp.status_code in (200, 201), resp.text
    body = resp.json()
    assert body["state"] == "submitted"
    assert body["week"]["mon"] == 8

