import pytest
import requests

def test_submit_timesheet_state_transition_draft_to_submitted(
    auth_fixture, base_url, create_draft_fixture
):
    token = auth_fixture()
    headers = {"Authorization": f"Bearer {token}"}
    draft_id = create_draft_fixture(token)
    payload = {
        "timesheet_id": draft_id,
        "week": {
            "mon": 8, "tue": 8, "wed": 8,
            "thu": 8, "fri": 8, "sat": 0, "sun": 0
        }
    }
    resp = requests.post(
        f"{base_url}/timesheets/submit",
        json=payload,
        headers=headers
    )
    assert resp.status_code in (200, 201), resp.text
    get_resp = requests.get(
        f"{base_url}/timesheets/{draft_id}",
        headers=headers
    )
    assert get_resp.status_code == 200
    assert get_resp.json()["state"] == "submitted"
